const BONUS_LABELS: Record<string, string> = {
  aceInvulnerable: 'Ace invulnerable',
  aceVsAce: 'Ace vs Ace',
  diamondDoubleDefense: 'Diamond \u00d72 def',
  clubDoubleOverflow: 'Club \u00d72 overflow',
  spadeDoubleLp: 'Spade \u00d72 LP',
  heartDeathShield: 'Heart Shield',
  diamondDeathShield: 'Diamond Shield',
};

export function renderBattlefield(
  gs: GameState,
  playerIdx: number,
  state: AppState,
  isOpponent: boolean,
): HTMLElement {
  const grid = el('div', 'battlefield');
  const battlefield = gs.players[playerIdx]?.battlefield;
  if (!battlefield) return grid;

  // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
  const rows = gs.params?.rows ?? 2;
  // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
  const columns = gs.params?.columns ?? 4;
  grid.style.gridTemplateColumns = `min-content repeat(${columns}, 1fr)`;

  // Column header row: empty corner + column numbers
  const corner = el('div', 'bf-col-label');
  grid.appendChild(corner);
  for (let c = 1; c <= columns; c++) {
    const colLabel = el('div', 'bf-col-label');
    colLabel.textContent = String(c);
    grid.appendChild(colLabel);
  }

  // Render rows: for opponent, show back row first then front row so front faces center
  // For self, show front row first then back row
  const rowOrder = isOpponent
    ? Array.from({ length: rows }, (_, i) => rows - 1 - i)
    : Array.from({ length: rows }, (_, i) => i);

  const rowName = (row: number): string => {
    if (row === 0) return 'Front';
    if (row === rows - 1) return 'Back';
    return `R${row + 1}`;
  };

  for (const row of rowOrder) {
    const rowLabel = el('div', 'bf-row-label');
    rowLabel.textContent = rowName(row);
    grid.appendChild(rowLabel);

    for (let col = 0; col < columns; col++) {
      const gridIdx = row * columns + col;
      const bCard = battlefield[gridIdx];
      const pos: GridPosition = { row, col };

      const cell = createBattlefieldCell(bCard, pos, isOpponent, gs);

      // Highlight reinforcement column on my battlefield
      const isReinforcementCol =
        !isOpponent && gs.phase === 'ReinforcementPhase' && col === gs.reinforcement?.column;
      if (isReinforcementCol) {
        cell.classList.add('reinforce-col');
        const canReinforce =
          state.selectedDeployCard !== null &&
          state.validActions.some(
            (a) => a.type === 'reinforce' && a.cardId === state.selectedDeployCard,
          );
        if (canReinforce) {
          cell.classList.add('valid-target');
          const doReinforce = (): void => {
            if (!state.matchId || state.playerIndex === null) return;
            getConnection()?.send({
              type: 'action',
              matchId: state.matchId,
              action: {
                type: 'reinforce',
                playerIndex: state.playerIndex,
                cardId: state.selectedDeployCard ?? '',
                timestamp: new Date().toISOString(),
              },
            });
          };
          cell.addEventListener('click', doReinforce);
          cell.addEventListener('keydown', (e) => {
            if (e.key === 'Enter' || e.key === ' ') {
              e.preventDefault();
              doReinforce();
            }
          });
        }
      }

      attachCellInteraction({ cell, bCard, pos, gs, state, isOpponent });
      grid.appendChild(cell);
    }
  }

  // Arrow key navigation within the grid
  grid.addEventListener('keydown', (e) => {
    if (!['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) return;
    const cells = Array.from(grid.querySelectorAll<HTMLElement>('.bf-cell'));
    const focusedIdx = cells.indexOf(document.activeElement as HTMLElement);
    if (focusedIdx === -1) return;
    e.preventDefault();
    let targetIdx = focusedIdx;
    if (e.key === 'ArrowLeft' && focusedIdx % columns > 0) targetIdx = focusedIdx - 1;
    else if (e.key === 'ArrowRight' && focusedIdx % columns < columns - 1)
      targetIdx = focusedIdx + 1;
    else if (e.key === 'ArrowUp' && focusedIdx >= columns) targetIdx = focusedIdx - columns;
    else if (e.key === 'ArrowDown' && focusedIdx < cells.length - columns)
      targetIdx = focusedIdx + columns;
    if (targetIdx !== focusedIdx) cells[targetIdx]?.focus();
  });

  return grid;
}

function renderHand(gs: GameState, state: AppState): HTMLElement {
  const handSection = el('div', 'hand-section');
  const label = el('div', 'section-label');
  label.textContent = 'Your Hand';
  handSection.appendChild(label);
  renderHelpMarker('hand', handSection);
  renderHelpMarker('reinforce', handSection);

  const handDiv = el('div', 'hand');
  const myIdx = state.playerIndex ?? 0;
  const hand = gs.players[myIdx]?.hand ?? [];

  for (let i = 0; i < hand.length; i++) {
    const card = hand[i];
    if (!card) continue;

    const cardEl = el('div', 'hand-card');
    cardEl.setAttribute('data-testid', `hand-card-${i}`);
    if (isFace(card)) cardEl.classList.add('is-face');
    cardEl.style.borderColor = suitColor(card.suit);

    applySuitAura(cardEl, card.suit);

    const rankEl = el('div', 'card-rank');
    rankEl.textContent = card.face;
    rankEl.style.color = suitColor(card.suit);
    cardEl.appendChild(rankEl);

    const suitEl = el('div', 'card-pip');
    suitEl.textContent = suitSymbol(card.suit);
    suitEl.style.color = suitColor(card.suit);
    cardEl.appendChild(suitEl);

    const isPlayable = state.validActions.some(
      (a) => (a.type === 'deploy' || a.type === 'reinforce') && a.cardId === card.id,
    );
    const isReinforcePlayable = state.validActions.some(
      (a) => a.type === 'reinforce' && a.cardId === card.id,
    );

    if (isPlayable) {
      cardEl.classList.add('playable');
      if (isReinforcePlayable) cardEl.classList.add('reinforce-playable');
      cardEl.setAttribute('tabindex', '0');
      if (state.selectedDeployCard === card.id) {
        cardEl.classList.add('selected');
      }
      cardEl.addEventListener('click', () => {
        selectDeployCard(card.id);
      });
      cardEl.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          selectDeployCard(card.id);
        }
      });
    }

    handDiv.appendChild(cardEl);
  }

  handSection.appendChild(handDiv);

  return handSection;
}

function renderBattleLog(gs: GameState): HTMLElement {
  const section = el('div', 'battle-log-section');
  const label = el('div', 'section-label');
  label.textContent = 'Battle Log';
  section.appendChild(label);
  renderHelpMarker('log', section);
  renderHelpMarker('target-chain', section);

  const logDiv = el('div', 'battle-log');
  const entries: CombatLogEntry[] = (gs.transactionLog ?? [])
    .filter((e) => e.details.type === 'attack')
    .map((e) => (e.details as { type: 'attack'; combat: CombatLogEntry }).combat);
  const recent = entries.slice(-8);

  for (const entry of recent) {
    const entryEl = el('div', 'log-entry');
    const atkLabel = cardLabel(entry.attackerCard);
    const parts: string[] = [`T${entry.turnNumber}: ${atkLabel} -> Col ${entry.targetColumn + 1}:`];

    for (const step of entry.steps) {
      if (step.target === 'playerLp') {
        let text = `LP ${step.lpBefore ?? '?'}\u2192${step.lpAfter ?? '?'} (-${step.damage})`;
        const bonusText = (step.bonuses ?? []).map((b) => BONUS_LABELS[b] ?? b).join(', ');
        if (bonusText) text += ` (${bonusText})`;
        parts.push(text);
      } else {
        const pos = step.target === 'frontCard' ? 'F' : 'B';
        const stepCard = step.card ? cardLabel(step.card) : '?';
        let text = `${stepCard} [${pos} ${step.hpBefore ?? '?'}\u2192${step.hpAfter ?? '?'}`;
        if (step.destroyed) text += ' KO';
        text += ']';
        const bonusText = (step.bonuses ?? []).map((b) => BONUS_LABELS[b] ?? b).join(', ');
        if (bonusText) text += ` (${bonusText})`;
        const carry = step.remaining ?? step.overflow ?? 0;
        if (carry > 0) text += ` \u2192${carry}\u2192`;
        parts.push(text);
      }
    }

    entryEl.textContent = parts.join(' ');
    logDiv.appendChild(entryEl);
  }

  section.appendChild(logDiv);
  return section;
}

export function renderStatsBlock(gs: GameState, playerIdx: number, isMine: boolean): HTMLElement {
  const ps = gs.players[playerIdx];
  const block = el('div', `stats-block ${isMine ? 'mine' : 'opponent'}`);
  renderHelpMarker('lp', block);

  const lp = getLifepoints(gs, playerIdx);
  const handCount = ps?.handCount ?? ps?.hand.length ?? 0;
  const deckCount = ps?.drawpileCount ?? ps?.drawpile.length ?? 0;
  const gyCount = ps?.discardPileCount ?? ps?.discardPile.length ?? 0;
  const lastCard = ps?.discardPile.at(-1);

  const stats = [
    { label: 'LP', value: String(lp) },
    { label: 'Hand', value: String(handCount).padStart(2, '0') },
    { label: 'Deck', value: String(deckCount).padStart(2, '0') },
    { label: 'GY', value: String(gyCount).padStart(2, '0') },
  ];

  const passState = gs.passState;
  const consecutive = passState?.consecutivePasses[playerIdx] ?? 0;
  const total = passState?.totalPasses[playerIdx] ?? 0;

  if (consecutive > 0 || total > 0) {
    stats.push({ label: 'Pass', value: `${consecutive}/${total}` });
  }

  if (isMine) {
    if (consecutive >= 2 || total >= 4) {
      const warning = el('div', 'pass-warning-badge');
      warning.textContent = 'FORFEIT RISK';
      warning.title = 'You are 1 pass away from automatic forfeit (3 consecutive or 5 total)';
      block.appendChild(warning);
    }
    if (lastCard) block.appendChild(makeCardStatsRow(lastCard, 'last'));
    stats.reverse().forEach((s) => block.appendChild(makeStatsRow(s.value, s.label)));
  } else {
    stats.forEach((s) => block.appendChild(makeStatsRow(s.value, s.label)));
    if (lastCard) block.appendChild(makeCardStatsRow(lastCard, 'last'));
  }

  return block;
}

function renderStatsSidebar(
  gs: GameState,
  myIdx: number,
  oppIdx: number,
  spectatorCount: number,
): HTMLElement {
  const sidebar = el('aside', 'stats-sidebar');
  sidebar.setAttribute('aria-label', 'Match statistics');
  const isMyTurn = gs.activePlayerIndex === myIdx;
  renderHelpMarker('stats', sidebar);

  sidebar.appendChild(renderStatsBlock(gs, oppIdx, false));
  sidebar.appendChild(document.createElement('hr')).className = 'stats-divider';

  const turnEl = el('div', 'stats-turn-number');
  turnEl.textContent = `T${gs.turnNumber}`;
  sidebar.appendChild(turnEl);

  const turnLabel = el('div', 'stats-turn');
  turnLabel.textContent = isMyTurn ? 'YOUR TURN' : 'OPP';
  turnLabel.classList.add(isMyTurn ? 'my-turn' : 'opp-turn');
  sidebar.appendChild(turnLabel);

  if (spectatorCount > 0) {
    const spectatorEl = el('div', 'spectator-count');
    spectatorEl.textContent = `${spectatorCount} watching`;
    sidebar.appendChild(spectatorEl);
  }

  sidebar.appendChild(document.createElement('hr')).className = 'stats-divider';
  sidebar.appendChild(renderStatsBlock(gs, myIdx, true));
  sidebar.appendChild(document.createElement('hr')).className = 'stats-divider';
  sidebar.appendChild(renderHealthBadge(getState().serverHealth));

  return sidebar;
}

function buildActionGroup(
  gameActions: ActionButtonDescriptor[],
  gs: GameState,
  state: AppState,
  myIdx: number,
): HTMLElement {
  const actionGroup = el('div', 'info-action-buttons');
  for (const btn of gameActions) {
    const btnEl = el('button', `btn btn-small${btn.className ? ` ${btn.className}` : ''}`);
    btnEl.textContent = btn.label;
    if (btn.testId) btnEl.setAttribute('data-testid', btn.testId);
    if (btn.label === 'Cancel') {
      btnEl.addEventListener('click', clearSelection);
    } else if (btn.label === 'Pass') {
      btnEl.addEventListener('click', () => {
        if (!state.matchId) return;
        const passState = gs.passState;
        const maxConsecutive = gs.params.modePassRules.maxConsecutivePasses;
        const maxTotal = gs.params.modePassRules.maxTotalPassesPerPlayer;
        const consecutive = passState?.consecutivePasses[myIdx] ?? 0;
        const total = passState?.totalPasses[myIdx] ?? 0;
        if (consecutive >= maxConsecutive - 1 || total >= maxTotal - 1) {
          const msg =
            consecutive >= maxConsecutive - 1
              ? `This will be your ${maxConsecutive}th consecutive pass. You will FORFEIT the match. Continue?`
              : `This will be your ${maxTotal}th total pass. You will FORFEIT the match. Continue?`;
          if (!confirm(msg)) return;
        }
        getConnection()?.send({
          type: 'action',
          matchId: state.matchId,
          action: { type: 'pass', playerIndex: myIdx, timestamp: new Date().toISOString() },
        });
      });
    } else if (btn.label === 'Skip') {
      btnEl.addEventListener('click', () => {
        if (!state.matchId) return;
        getConnection()?.send({
          type: 'action',
          matchId: state.matchId,
          action: { type: 'pass', playerIndex: myIdx, timestamp: new Date().toISOString() },
        });
      });
      btnEl.title = 'Skipping reinforcement is free (does not count toward pass limits)';
    } else if (btn.label === 'Forfeit') {
      btnEl.addEventListener('click', () => {
        if (!state.matchId) return;
        if (!confirm('Are you sure you want to forfeit?')) return;
        getConnection()?.send({
          type: 'action',
          matchId: state.matchId,
          action: { type: 'forfeit', playerIndex: myIdx, timestamp: new Date().toISOString() },
        });
      });
    }
    actionGroup.appendChild(btnEl);
  }
  return actionGroup;
}

function renderInGameInvite(state: AppState): HTMLElement {
  const section = el('div', 'in-game-invite');
  const label = el('span', 'invite-label');
  label.textContent = 'Invite Spectators:';
  section.appendChild(label);

  const btnRow = el('div', 'share-btn-row');

  const copyCode = makeCopyBtn('Code', () => state.matchId ?? '');
  copyCode.classList.add('btn-tiny');
  btnRow.appendChild(copyCode);

  const copyLink = makeCopyBtn('Link', () => {
    const url = new URL(window.location.href);
    url.searchParams.set('watch', state.matchId ?? '');
    return url.toString();
  });
  copyLink.classList.add('btn-tiny');
  btnRow.appendChild(copyLink);

  section.appendChild(btnRow);
  return section;
}

export function renderGame(container: HTMLElement, state: AppState): void {
  if (!state.gameState) return;
  if (!state.isSpectator && state.playerIndex === null) return;

  const gs = state.gameState;
  const isSpectator = state.isSpectator;
  const myIdx = isSpectator ? 0 : (state.playerIndex ?? 0);
  const oppIdx = myIdx === 0 ? 1 : 0;

  const layout = el('div', 'game-layout');
  layout.setAttribute('data-testid', 'game-layout');

  const main = el('main', 'game-main');
  main.setAttribute('aria-label', 'Game area');
  const wrapper = el('div', 'game');

  // Opponent battlefield (top, mirrored)
  const oppSection = el('section', 'battlefield-section opponent');
  oppSection.setAttribute(
    'aria-label',
    `${gs.players[oppIdx]?.player.name ?? 'Opponent'} battlefield`,
  );
  const oppLabel = el('div', 'section-label');
  oppLabel.textContent = gs.players[oppIdx]?.player.name ?? 'Opponent';
  oppSection.appendChild(oppLabel);
  oppSection.appendChild(renderBattlefield(gs, oppIdx, state, true));
  if (!isSpectator) renderHelpMarker('battlefield', oppSection);
  wrapper.appendChild(oppSection);

  // Info bar
  const turnInfo = getTurnIndicatorText(gs, isSpectator, myIdx);
  const infoBar = el('header', 'info-bar');
  infoBar.classList.add(turnInfo.isMyTurn ? 'is-my-turn' : 'is-opp-turn');

  // Meta section: phase + turn count + turn status
  const meta = el('div', 'info-bar-top');

  const phaseLabel = getPhaseLabel(gs);
  const phaseText = el('span', 'phase-value');
  phaseText.textContent = phaseLabel;
  phaseText.setAttribute('data-testid', 'phase-indicator');
  meta.appendChild(phaseText);

  const turnCount = el('span', 'turn-count');
  turnCount.textContent = `T${gs.turnNumber}`;
  meta.appendChild(turnCount);

  if (isSpectator) {
    const spectatorBadge = el('span', 'spectator-indicator');
    spectatorBadge.textContent = 'SPECTATING';
    meta.appendChild(spectatorBadge);
  }

  if (gs.gameOptions?.damageMode === 'classic') {
    const modeTag = el('span', 'mode-tag');
    modeTag.textContent = 'Per-Turn Reset';
    meta.appendChild(modeTag);
  }

  const turnText = el('span', 'turn-status');
  turnText.setAttribute('data-testid', 'turn-indicator');
  turnText.setAttribute('role', 'status');
  turnText.setAttribute('aria-live', 'polite');
  turnText.setAttribute('aria-atomic', 'true');
  turnText.textContent = turnInfo.text;
  turnText.classList.add(turnInfo.isMyTurn ? 'status-my-turn' : 'status-opp-turn');
  meta.appendChild(turnText);

  infoBar.appendChild(meta);

  // Action buttons (Cancel / Pass / Skip / Forfeit) grouped together
  const actionButtons = getActionButtons({
    gs,
    isSpectator,
    myIdx,
    selectedAttacker: state.selectedAttacker,
    showHelp: state.showHelp,
    validActions: state.validActions,
  });
  const gameActions = actionButtons.filter((b) => b.className !== 'help-btn');
  const helpAction = actionButtons.find((b) => b.className === 'help-btn');

  if (gameActions.length > 0) {
    const actionGroup = buildActionGroup(gameActions, gs, state, myIdx);
    renderHelpMarker('pass-forfeit', actionGroup);
    infoBar.appendChild(actionGroup);
  }

  // Help button — always present, pushed to far right
  if (helpAction) {
    const helpEl = el('button', `btn btn-small ${helpAction.className ?? ''}`);
    helpEl.textContent = helpAction.label;
    helpEl.addEventListener('click', toggleHelp);
    infoBar.appendChild(helpEl);
  }

  wrapper.appendChild(infoBar);

  // My battlefield (bottom)
  const mySection = el('section', 'battlefield-section mine');
  mySection.setAttribute('aria-label', `${gs.players[myIdx]?.player.name ?? 'Your'} battlefield`);
  const myLabel = el('div', 'section-label');
  myLabel.textContent = gs.players[myIdx]?.player.name ?? 'You';
  mySection.appendChild(myLabel);
  mySection.appendChild(renderBattlefield(gs, myIdx, state, false));
  if (!isSpectator) renderHelpMarker('suits', mySection);
  wrapper.appendChild(mySection);

  // Hidden assertive live region for game-critical events (forfeit risk, game over)
  const alertRegion = el('div', 'sr-only');
  alertRegion.setAttribute('role', 'alert');
  alertRegion.setAttribute('aria-live', 'assertive');
  alertRegion.setAttribute('aria-atomic', 'true');
  wrapper.appendChild(alertRegion);

  if (!isSpectator && gs.players[myIdx]) {
    wrapper.appendChild(renderHand(gs, state));
  }

  // Battle log
  const hasAttacks = (gs.transactionLog ?? []).some((e) => e.details.type === 'attack');
  if (hasAttacks) {
    wrapper.appendChild(renderBattleLog(gs));
  }

  // Invite section (discrete)
  if (!isSpectator) {
    wrapper.appendChild(renderInGameInvite(state));
  }

  main.appendChild(wrapper);
  layout.appendChild(main);
  layout.appendChild(renderStatsSidebar(gs, myIdx, oppIdx, state.spectatorCount));
  container.appendChild(layout);
  restoreFocus(layout, container);
}

/**
 * After a full re-render, focus the most relevant interactive element so keyboard users
 * don't need to re-orient. Only acts when focus was on body (i.e. lost due to innerHTML='').
 */
function restoreFocus(layout: HTMLElement, container: HTMLElement): void {
  const ae = document.activeElement;
  if (ae && ae !== document.body && ae !== container) return;
  const target =
    layout.querySelector<HTMLElement>('.bf-cell.selected') ??
    layout.querySelector<HTMLElement>('.bf-cell.valid-target') ??
    layout.querySelector<HTMLElement>('.hand-card.selected') ??
    layout.querySelector<HTMLElement>('.hand-card.playable') ??
    layout.querySelector<HTMLElement>('.pz-active-pulse');
  target?.focus({ preventScroll: true });
}

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { createConnection, type ConnectionLifecycleState } from '../src/connection';
import { setToken } from '../src/auth';

type WsListener = (event: unknown) => void;

class MockWebSocket {
  static OPEN = 1;
  static CLOSED = 3;
  static instances: MockWebSocket[] = [];

  url: string;
  readyState = MockWebSocket.OPEN;
  private listeners: Record<string, WsListener[]> = {};

  constructor(url: string) {
    this.url = url;
    MockWebSocket.instances.push(this);
  }

  addEventListener(event: string, cb: WsListener) {
    (this.listeners[event] ??= []).push(cb);
  }

  send = vi.fn();
  close = vi.fn((code?: number, reason?: string) => {
    this.readyState = MockWebSocket.CLOSED;
    this.fire('close', { code, reason });
  });

  fire(event: string, data?: unknown) {
    for (const cb of this.listeners[event] ?? []) {
      cb(data ?? {});
    }
  }
}

Object.defineProperty(MockWebSocket, 'OPEN', { value: 1 });
Object.defineProperty(MockWebSocket, 'CLOSED', { value: 3 });

describe('createConnection', () => {
  const sessionStore: Record<string, string> = {};
  let onMessage: ReturnType<
    typeof vi.fn<(message: import('@phalanxduel/shared').ServerMessage) => void>
  >;
  let onStateChange: ReturnType<typeof vi.fn<(state: ConnectionLifecycleState) => void>>;

  beforeEach(() => {
    vi.useFakeTimers();
    vi.spyOn(Math, 'random').mockReturnValue(0);
    MockWebSocket.instances = [];
    vi.stubGlobal('WebSocket', MockWebSocket);
    vi.stubGlobal('sessionStorage', {
      getItem: vi.fn((key: string) => sessionStore[key] ?? null),
      setItem: vi.fn((key: string, value: string) => {
        sessionStore[key] = value;
      }),
      removeItem: vi.fn((key: string) => {
        delete sessionStore[key];
      }),
    });
    onMessage = vi.fn();
    onStateChange = vi.fn();
    vi.clearAllMocks();
    setToken(null);
    for (const key of Object.keys(sessionStore)) delete sessionStore[key];
  });

  afterEach(() => {
    vi.restoreAllMocks();
    vi.useRealTimers();
    vi.unstubAllGlobals();
    setToken(null);
  });

  function lastWs(): MockWebSocket {
    return MockWebSocket.instances[MockWebSocket.instances.length - 1]!;
  }

  it('starts in CONNECTING and transitions to OPEN on socket open', () => {
    createConnection('ws://test:3001', onMessage, { onStateChange });
    expect(onStateChange).toHaveBeenCalledWith('CONNECTING');

    lastWs().fire('open');

    expect(onStateChange).toHaveBeenLastCalledWith('OPEN');
  });

  it('serializes reliable messages with msgId and telemetry', () => {
    const conn = createConnection('ws://test:3001', onMessage);
    const ws = lastWs();
    ws.fire('open');

    conn.send({
      type: 'createMatch',
      playerName: 'Alice',
      gameOptions: {
        damageMode: 'classic',
        startingLifepoints: 20,
        classicDeployment: true,
      },
    });

    const sent = JSON.parse(String(ws.send.mock.calls.at(-1)?.[0]));
    expect(sent).toMatchObject({
      type: 'createMatch',
      playerName: 'Alice',
      msgId: expect.any(String),
      telemetry: {
        originService: 'phx-client',
        reconnectAttempt: 0,
        sessionId: expect.any(String),
      },
    });
  });

  it('removes pending messages when the server ACKs them', () => {
    const conn = createConnection('ws://test:3001', onMessage);
    const ws = lastWs();
    ws.fire('open');

    conn.send({
      type: 'joinMatch',
      matchId: '3dff75bd-e19d-4ae6-99e4-bf6607ed58cb',
      playerName: 'Alice',
    });

    const outbound = JSON.parse(String(ws.send.mock.calls.at(-1)?.[0]));
    ws.send.mockClear();

    ws.fire('message', {
      data: JSON.stringify({ type: 'ack', ackedMsgId: outbound.msgId }),
    });

    ws.fire('close');
    vi.advanceTimersByTime(1000);
    lastWs().fire('open');

    expect(lastWs().send).not.toHaveBeenCalledWith(JSON.stringify(outbound));
  });

  it('flushes pending reliable messages after reconnect', () => {
    const conn = createConnection('ws://test:3001', onMessage);
    const ws = lastWs();
    ws.fire('open');

    conn.send({
      type: 'joinMatch',
      matchId: '3dff75bd-e19d-4ae6-99e4-bf6607ed58cb',
      playerName: 'Alice',
    });

    const outbound = JSON.parse(String(ws.send.mock.calls.at(-1)?.[0]));

    ws.fire('close');
    vi.advanceTimersByTime(1000);
    const reconnected = lastWs();
    reconnected.fire('open');

    const resent = reconnected.send.mock.calls
      .map((call) => JSON.parse(String(call[0])))
      .find((message) => message.type === 'joinMatch');
    expect(resent).toMatchObject({
      type: 'joinMatch',
      matchId: outbound.matchId,
      msgId: outbound.msgId,
    });
  });

  it('responds to server ping messages with pong', () => {
    createConnection('ws://test:3001', onMessage);
    const ws = lastWs();
    ws.fire('open');
    ws.send.mockClear();

    ws.fire('message', {
      data: JSON.stringify({
        type: 'ping',
        msgId: '20edcac1-2ca3-4d6a-9ca8-5b83a059d47d',
        timestamp: new Date().toISOString(),
      }),
    });

    const sent = JSON.parse(String(ws.send.mock.calls.at(-1)?.[0]));
    expect(sent).toMatchObject({
      type: 'pong',
      replyTo: '20edcac1-2ca3-4d6a-9ca8-5b83a059d47d',
    });
  });

  it('closes and reconnects when heartbeat times out', () => {
    createConnection('ws://test:3001', onMessage, { onStateChange });
    const ws = lastWs();
    ws.fire('open');

    vi.advanceTimersByTime(70_000);

    expect(ws.close).toHaveBeenCalledWith(4001, 'Heartbeat timeout');
    expect(onStateChange).toHaveBeenCalledWith('DISCONNECTED');
    vi.advanceTimersByTime(1000);
    expect(MockWebSocket.instances.length).toBeGreaterThan(1);
  });

  it('sends rejoinMatch before flushing queued messages when a saved session exists', () => {
    sessionStore.phalanx_session = JSON.stringify({
      matchId: '0be0719d-6d98-4f10-9ff3-42535a9b6151',
      playerId: '5d9ab163-f763-4489-ab74-fdaa54a8f7c6',
      playerIndex: 0,
      playerName: 'Alice',
    });

    const conn = createConnection('ws://test:3001', onMessage);
    const ws = lastWs();
    conn.send({
      type: 'action',
      matchId: '0be0719d-6d98-4f10-9ff3-42535a9b6151',
      action: {
        type: 'forfeit',
        playerIndex: 0,
        timestamp: new Date().toISOString(),
      },
    });

    ws.fire('open');

    const firstSent = JSON.parse(String(ws.send.mock.calls.at(-1)?.[0]));
    expect(firstSent.type).toBe('rejoinMatch');

    ws.fire('message', {
      data: JSON.stringify({
        type: 'matchJoined',
        matchId: '0be0719d-6d98-4f10-9ff3-42535a9b6151',
        playerId: '5d9ab163-f763-4489-ab74-fdaa54a8f7c6',
        playerIndex: 0,
      }),
    });

    const sentTypes = ws.send.mock.calls.map((call) => JSON.parse(String(call[0])).type);
    expect(sentTypes).toContain('action');
  });
});

import { mkdtemp, writeFile, rm } from 'node:fs/promises';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { describe, expect, it } from 'vitest';
import { generateScenario, GameScenarioSchema, loadScenario } from '../../bin/qa/scenario';

describe('QA scenario contract', () => {
  it('generates a schema-valid scenario with deterministic action content', () => {
    const scenario = generateScenario(42, 'classic', 20, 'bot-random', 'bot-heuristic');
    const parsed = GameScenarioSchema.parse(scenario);

    expect(parsed.version).toBe(1);
    expect(parsed.seed).toBe(42);
    expect(parsed.damageMode).toBe('classic');
    expect(parsed.startingLifepoints).toBe(20);
    expect(parsed.p1).toBe('bot-random');
    expect(parsed.p2).toBe('bot-heuristic');
    expect(parsed.actions.length).toBeGreaterThan(0);
    expect(parsed.actions[0]?.type).toBeDefined();
  });

  it('loads and validates a scenario file from disk', async () => {
    const tempDir = await mkdtemp(join(tmpdir(), 'phx-scenario-'));
    const scenarioPath = join(tempDir, 'scenario.json');
    const scenario = generateScenario(7, 'cumulative', 100, 'bot-heuristic', 'bot-heuristic');

    try {
      await writeFile(scenarioPath, `${JSON.stringify(scenario, null, 2)}\n`, 'utf8');

      const loaded = await loadScenario(scenarioPath);
      expect(loaded).toEqual(GameScenarioSchema.parse(scenario));
    } finally {
      await rm(tempDir, { recursive: true, force: true });
    }
  });
});

import { db } from './index.js';
import { matches, transactionLogs } from './schema.js';
import { desc, eq, asc } from 'drizzle-orm';
import type { MatchInstance } from '../match.js';
import type {
  GameState,
  Action,
  MatchEventLog,
  TransactionLogEntry,
  PhalanxEvent,
} from '@phalanxduel/shared';
import type { GameConfig } from '@phalanxduel/engine';
import { traceDbQuery } from './observability.js';
import { TelemetryName } from '@phalanxduel/shared';

function isLifecycleEvent(event: PhalanxEvent): boolean {
  return (
    event.name === 'match.created' ||
    event.name === 'player.joined' ||
    event.name === TelemetryName.EVENT_PLAYER_DISCONNECTED ||
    event.name === TelemetryName.EVENT_PLAYER_RECONNECTED ||
    event.name === 'game.initialized' ||
    event.name === 'game.completed'
  );
}

export interface MatchSummary {
  matchId: string;
  playerIds: (string | null)[];
  playerNames: string[];
  winnerIndex: number | null;
  victoryType: string | null;
  turnCount: number | null;
  fingerprint: string | null;
  createdAt: string;
  completedAt: string;
}

interface RecoverPlayerParams {
  playerName: string | null;
  playerId: string;
  playerIndex: 0 | 1;
  userId: string | null;
  disconnectedAt?: string;
}

function recoverPlayer({
  playerName,
  playerId,
  playerIndex,
  userId,
  disconnectedAt,
}: RecoverPlayerParams) {
  if (!playerName) return null;
  return {
    playerId,
    playerName,
    playerIndex,
    userId: userId ?? undefined,
    socket: null,
    disconnectedAt,
  };
}

function recoverDisconnectedAtByPlayer(
  row: typeof matches.$inferSelect,
): Partial<Record<0 | 1, string>> {
  const persistedEventLog = row.eventLog as MatchEventLog | null;
  const disconnectedAtByPlayer: Partial<Record<0 | 1, string>> = {};

  for (const event of persistedEventLog?.events ?? []) {
    if (
      event.name !== TelemetryName.EVENT_PLAYER_DISCONNECTED &&
      event.name !== TelemetryName.EVENT_PLAYER_RECONNECTED
    ) {
      continue;
    }

    const payload = event.payload as { playerIndex?: number; disconnectedAt?: string } | null;
    const playerIndex = payload?.playerIndex;
    if (playerIndex !== 0 && playerIndex !== 1) continue;

    if (event.name === TelemetryName.EVENT_PLAYER_DISCONNECTED) {
      disconnectedAtByPlayer[playerIndex] = payload?.disconnectedAt ?? event.timestamp;
      continue;
    }

    delete disconnectedAtByPlayer[playerIndex];
  }

  return disconnectedAtByPlayer;
}

function recoverPlayers(
  row: typeof matches.$inferSelect,
  config: GameConfig | null,
): MatchInstance['players'] {
  const playerConfig = config?.players ?? [];
  const player0Id = playerConfig[0]?.id ?? 'recovered-p1';
  const player1Id = playerConfig[1]?.id ?? 'recovered-p2';
  const disconnectedAtByPlayer = recoverDisconnectedAtByPlayer(row);

  return [
    recoverPlayer({
      playerName: row.player1Name,
      playerId: player0Id,
      playerIndex: 0,
      userId: row.player1Id,
      disconnectedAt: disconnectedAtByPlayer[0],
    }),
    recoverPlayer({
      playerName: row.player2Name,
      playerId: player1Id,
      playerIndex: 1,
      userId: row.player2Id,
      disconnectedAt: disconnectedAtByPlayer[1],
    }),
  ];
}

function recoverLifecycleEvents(row: typeof matches.$inferSelect) {
  const persistedEventLog = row.eventLog as MatchEventLog | null;
  return persistedEventLog?.events.filter(isLifecycleEvent) ?? [];
}

function buildRecoveredMatch(row: typeof matches.$inferSelect): MatchInstance {
  const config = row.config as GameConfig | null;
  const botStrategy = row.botStrategy ?? undefined;

  return {
    matchId: row.id,
    players: recoverPlayers(row, config),
    spectators: [],
    state: row.state as GameState,
    config,
    actionHistory: row.actionHistory as Action[],
    gameOptions: config?.gameOptions,
    rngSeed: config?.rngSeed,
    matchParams: config?.matchParams,
    botConfig:
      botStrategy && config
        ? {
            strategy: botStrategy,
            seed: config.rngSeed,
          }
        : undefined,
    botPlayerIndex: botStrategy ? 1 : undefined,
    lastPreState: null,
    lifecycleEvents: recoverLifecycleEvents(row),
    createdAt: row.createdAt.getTime(),
    lastActivityAt: row.updatedAt.getTime(),
    botStrategy,
  };
}

export class MatchRepository {
  async saveMatch(match: MatchInstance): Promise<void> {
    const database = db;
    if (!database) return;
    if (!match.config) return;

    const payload = {
      id: match.matchId,
      player1Id: match.players[0]?.userId ?? null,
      player2Id: match.players[1]?.userId ?? null,
      player1Name: match.players[0]?.playerName ?? 'Unknown',
      player2Name: match.players[1]?.playerName ?? 'Unknown',
      botStrategy: match.botStrategy ?? null,
      config: match.config,
      state: match.state,
      actionHistory: match.actionHistory,
      transactionLog: match.state?.transactionLog ?? [],
      outcome: match.state?.outcome ?? null,
      status: (match.state?.phase === 'gameOver' ? 'completed' : 'active') as
        | 'pending'
        | 'active'
        | 'completed'
        | 'cancelled',
      updatedAt: new Date(),
    };

    try {
      await traceDbQuery(
        'db.matches.upsert',
        {
          operation: 'UPSERT',
          table: 'matches',
        },
        () =>
          database
            .insert(matches)
            .values({
              ...payload,
              createdAt: new Date(match.createdAt),
            })
            .onConflictDoUpdate({
              target: matches.id,
              set: payload,
            }),
      );
    } catch (err) {
      console.error('Failed to save match to database:', err);
    }
  }

  async getCompletedMatches(page: number, limit: number): Promise<MatchSummary[]> {
    const database = db;
    if (!database) return [];

    try {
      const offset = (page - 1) * limit;
      const rows = await traceDbQuery(
        'db.matches.select_completed',
        { operation: 'SELECT', table: 'matches' },
        () =>
          database
            .select({
              id: matches.id,
              player1Id: matches.player1Id,
              player2Id: matches.player2Id,
              player1Name: matches.player1Name,
              player2Name: matches.player2Name,
              outcome: matches.outcome,
              eventLogFingerprint: matches.eventLogFingerprint,
              createdAt: matches.createdAt,
              updatedAt: matches.updatedAt,
            })
            .from(matches)
            .where(eq(matches.status, 'completed'))
            .orderBy(desc(matches.createdAt))
            .limit(limit)
            .offset(offset),
      );

      return rows.map((row) => {
        const outcome = row.outcome as {
          winnerIndex?: number | null;
          victoryType?: string | null;
          turnNumber?: number | null;
        } | null;
        return {
          matchId: row.id,
          playerIds: [row.player1Id ?? null, row.player2Id ?? null],
          playerNames: [row.player1Name, row.player2Name],
          winnerIndex: outcome?.winnerIndex ?? null,
          victoryType: outcome?.victoryType ?? null,
          turnCount: outcome?.turnNumber ?? null,
          fingerprint: row.eventLogFingerprint ?? null,
          createdAt: row.createdAt.toISOString(),
          completedAt: row.updatedAt.toISOString(),
        };
      });
    } catch (err) {
      console.error('Failed to get completed matches from database:', err);
      return [];
    }
  }

  async saveEventLog(matchId: string, log: MatchEventLog): Promise<void> {
    const database = db;
    if (!database) return;

    try {
      await traceDbQuery(
        'db.matches.update_event_log',
        { operation: 'UPDATE', table: 'matches' },
        () =>
          database
            .update(matches)
            .set({ eventLog: log, eventLogFingerprint: log.fingerprint })
            .where(eq(matches.id, matchId)),
      );
    } catch (err) {
      console.error('Failed to save event log to database:', err);
    }
  }

  async getEventLog(matchId: string): Promise<MatchEventLog | null> {
    const database = db;
    if (!database) return null;

    try {
      const result = await traceDbQuery(
        'db.matches.select_event_log',
        { operation: 'SELECT', table: 'matches' },
        () =>
          database
            .select({ eventLog: matches.eventLog })
            .from(matches)
            .where(eq(matches.id, matchId))
            .limit(1),
      );
      const row = result[0];
      if (!row?.eventLog) return null;
      return row.eventLog as MatchEventLog;
    } catch (err) {
      console.error('Failed to get event log from database:', err);
      return null;
    }
  }

  async getMatch(matchId: string): Promise<MatchInstance | null> {
    const database = db;
    if (!database) return null;

    try {
      const result = await traceDbQuery(
        'db.matches.select_by_id',
        {
          operation: 'SELECT',
          table: 'matches',
        },
        () => database.select().from(matches).where(eq(matches.id, matchId)).limit(1),
      );
      if (result.length === 0) return null;

      const row = result[0];
      if (!row) return null;
      return buildRecoveredMatch(row);
    } catch (err) {
      console.error('Failed to get match from database:', err);
      return null;
    }
  }

  async saveTransactionLogEntry(
    matchId: string,
    sequenceNumber: number,
    entry: TransactionLogEntry,
    events: PhalanxEvent[],
  ): Promise<void> {
    const database = db;
    if (!database) return;

    try {
      await traceDbQuery(
        'db.transaction_logs.insert',
        { operation: 'INSERT', table: 'transaction_logs' },
        () =>
          database.insert(transactionLogs).values({
            matchId,
            sequenceNumber,
            action: entry.action,
            stateHashBefore: entry.stateHashBefore,
            stateHashAfter: entry.stateHashAfter,
            events,
          }),
      );
    } catch (err) {
      console.error('Failed to save transaction log entry:', err);
    }
  }

  async saveFinalStateHash(matchId: string, hash: string): Promise<void> {
    const database = db;
    if (!database) return;

    try {
      await traceDbQuery(
        'db.matches.update_final_hash',
        { operation: 'UPDATE', table: 'matches' },
        () => database.update(matches).set({ finalStateHash: hash }).where(eq(matches.id, matchId)),
      );
    } catch (err) {
      console.error('Failed to save final state hash:', err);
    }
  }

  async getFinalStateHash(matchId: string): Promise<string | null> {
    const database = db;
    if (!database) return null;

    try {
      const result = await traceDbQuery(
        'db.matches.select_final_hash',
        { operation: 'SELECT', table: 'matches' },
        () =>
          database
            .select({ finalStateHash: matches.finalStateHash })
            .from(matches)
            .where(eq(matches.id, matchId))
            .limit(1),
      );
      return result[0]?.finalStateHash ?? null;
    } catch (err) {
      console.error('Failed to get final state hash:', err);
      return null;
    }
  }

  /**
   * Verify hash chain continuity for a match's transaction log.
   * Each entry's stateHashBefore must equal the previous entry's stateHashAfter.
   */
  async verifyHashChain(matchId: string): Promise<{
    valid: boolean;
    actionCount: number;
    finalStateHash: string | null;
    error?: string;
    failedAtSequence?: number;
  }> {
    const database = db;
    if (!database)
      return {
        valid: false,
        actionCount: 0,
        finalStateHash: null,
        error: 'Database not available',
      };

    try {
      const rows = await traceDbQuery(
        'db.transaction_logs.select_hashes',
        { operation: 'SELECT', table: 'transaction_logs' },
        () =>
          database
            .select({
              sequenceNumber: transactionLogs.sequenceNumber,
              stateHashBefore: transactionLogs.stateHashBefore,
              stateHashAfter: transactionLogs.stateHashAfter,
            })
            .from(transactionLogs)
            .where(eq(transactionLogs.matchId, matchId))
            .orderBy(asc(transactionLogs.sequenceNumber)),
      );

      if (rows.length === 0) {
        return {
          valid: false,
          actionCount: 0,
          finalStateHash: null,
          error: 'No transaction log entries found',
        };
      }

      for (let i = 1; i < rows.length; i++) {
        const prev = rows[i - 1];
        const curr = rows[i];
        if (!prev || !curr) continue;
        if (curr.stateHashBefore !== prev.stateHashAfter) {
          return {
            valid: false,
            actionCount: rows.length,
            finalStateHash: null,
            error: `Hash chain break at sequence ${curr.sequenceNumber}: expected ${prev.stateHashAfter}, got ${curr.stateHashBefore}`,
            failedAtSequence: curr.sequenceNumber,
          };
        }
      }

      const finalHash = rows.at(-1)?.stateHashAfter ?? null;
      return { valid: true, actionCount: rows.length, finalStateHash: finalHash };
    } catch (err) {
      console.error('Failed to verify hash chain:', err);
      return { valid: false, actionCount: 0, finalStateHash: null, error: 'Database query failed' };
    }
  }

  async getTransactionLog(matchId: string): Promise<TransactionLogEntry[]> {
    const database = db;
    if (!database) return [];

    try {
      const rows = await traceDbQuery(
        'db.transaction_logs.select_by_match',
        { operation: 'SELECT', table: 'transaction_logs' },
        () =>
          database
            .select()
            .from(transactionLogs)
            .where(eq(transactionLogs.matchId, matchId))
            .orderBy(asc(transactionLogs.sequenceNumber)),
      );

      return rows.map((row) => ({
        sequenceNumber: row.sequenceNumber,
        action: row.action as Action,
        stateHashBefore: row.stateHashBefore,
        stateHashAfter: row.stateHashAfter,
        timestamp: row.createdAt.toISOString(),
        details:
          (row.events as PhalanxEvent[]).find((e) => e.type === 'functional_update')?.payload ?? {},
      })) as unknown as TransactionLogEntry[];
    } catch (err) {
      console.error('Failed to get transaction log:', err);
      return [];
    }
  }
}

